import React, { useState, useEffect } from "react";
import axios from "axios";
import "./App.css";

const API_URL = "http://localhost:4000";

type RiskScore = "LOW" | "SUSPICIOUS" | "HIGH";
type Decision = "ALLOW" | "STEP_UP" | "BLOCK";

interface VerifyResult {
  phone: string;
  number_verified: boolean;
  sim_swap_recent: boolean;
  device_active: boolean;
  location_match: boolean;
  risk_score: RiskScore;
  decision: Decision;
  timestamp: string;
}

// Visual configurations
const RISK_CONFIG: Record<RiskScore, any> = {
  LOW: { label: "Safe", col: "var(--safe-color)", bg: "var(--safe-bg)", glow: "rgba(16,185,129,0.15)", border: "var(--safe-border)", Icon: ShieldCheck },
  SUSPICIOUS: { label: "Suspicious", col: "var(--warn-color)", bg: "var(--warn-bg)", glow: "rgba(245,158,11,0.15)", border: "var(--warn-border)", Icon: AlertTriangle },
  HIGH: { label: "High Risk", col: "var(--danger-color)", bg: "var(--danger-bg)", glow: "rgba(239,68,68,0.2)", border: "var(--danger-border)", Icon: ShieldX },
};

const DECISION_OPTS = {
  ALLOW: "Authorize Transaction",
  STEP_UP: "Trigger Step-Up KYC",
  BLOCK: "Deny Action & Alert Fraud Team"
};

// SVG Icons
function PhoneIcon() { return <svg fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502l4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z" /></svg>; }
function SearchIcon() { return <svg fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>; }
function ShieldCheck() { return <svg fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" /></svg>; }
function AlertTriangle() { return <svg fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>; }
function ShieldX() { return <svg fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>; }
function CheckIcon() { return <svg fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" /></svg>; }
function XIcon() { return <svg fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>; }
function CodeIcon() { return <svg fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>; }
function ChartIcon() { return <svg fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>; }
function EyeIcon() { return <svg fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>; }
function UserIcon() { return <svg fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>; }

const MOCK_LOADING_STEPS = [
  "Securing connection to CAMARA Enabler...",
  "Querying Home Location Register (HLR)...",
  "Analyzing latest SIM ICCID permutations...",
  "Pinging device node for active presence...",
  "Resolving geographic telemetry...",
  "Processing signals via Risk Engine..."
];

export default function App() {
  const [phone, setPhone] = useState("");
  const [simState, setSimState] = useState<"idle" | "loading" | "done">("idle");
  const [loadStepIndex, setLoadStepIndex] = useState(0);
  const [result, setResult] = useState<VerifyResult | null>(null);
  const [error, setError] = useState("");

  // New States
  const [activeView, setActiveView] = useState<"verify" | "dashboard" | "docs">("verify");
  const [isDevMode, setIsDevMode] = useState(false);
  const [showLiveness, setShowLiveness] = useState(false);
  const [livenessStatus, setLivenessStatus] = useState<"scanning" | "success">("scanning");
  const [stats, setStats] = useState<any>(null);

  useEffect(() => {
    if (simState === "loading") {
      const interval = setInterval(() => {
        setLoadStepIndex(i => {
          if (i >= MOCK_LOADING_STEPS.length - 1) {
            clearInterval(interval);
            return i;
          }
          return i + 1;
        });
      }, 400); 
      return () => clearInterval(interval);
    }
  }, [simState]);

  useEffect(() => {
    if (activeView === "dashboard") {
      fetchStats();
    }
  }, [activeView]);

  async function fetchStats() {
    try {
      const res = await axios.get(`${API_URL}/stats`);
      setStats(res.data);
    } catch (e) {
      console.error("Failed to fetch stats", e);
    }
  }

  function triggerLiveness() {
    setShowLiveness(true);
    setLivenessStatus("scanning");
    setTimeout(() => {
      setLivenessStatus("success");
    }, 3000);
  }

  async function verify(targetPhone: string) {
    if (!targetPhone.trim()) { setError("Enter a valid mobile operator number."); return; }
    setError("");
    setResult(null);
    setSimState("loading");
    setLoadStepIndex(0);
    setPhone(targetPhone); // update input visually

    try {
      // Intentionally delaying API call so the UI loading sequence shows
      const apiReq = axios.post<VerifyResult>(`${API_URL}/verify-user`, { phone: targetPhone });
      const timerReq = new Promise(resolve => setTimeout(resolve, 2500));

      const [res] = await Promise.all([apiReq, timerReq]);
      setResult(res.data);
      setSimState("done");
    } catch {
      setError("Network intelligence layer unavailable. Ensure the API is running on :4000.");
      setSimState("idle");
    }
  }

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && simState !== "loading") verify(phone);
  };

  return (
    <div className="app-container">
      {/* Animated Deep Background */}
      <div className="app-bg">
        <div className="orb orb-1"></div>
        <div className="orb orb-2"></div>
        <div className="orb orb-3"></div>
      </div>

      <nav className="navbar">
        <div className="nav-brand" onClick={() => setActiveView("verify")} style={{cursor: 'pointer'}}>
          <div className="brand-icon"><ShieldCheck /></div>
          <div className="brand-text-wrapper">
            <span className="brand-title">SimVerify API</span>
            <span className="brand-subtitle">Identity & Anti-Fraud</span>
          </div>
        </div>

        <div className="nav-nav">
          <button 
            className={`nav-link ${activeView === 'verify' ? 'active' : ''}`}
            onClick={() => setActiveView('verify')}
          >
            <ShieldCheck /> Security Verify
          </button>
          <button 
            className={`nav-link ${activeView === 'dashboard' ? 'active' : ''}`}
            onClick={() => setActiveView('dashboard')}
          >
            <ChartIcon /> Insights
          </button>
          <button 
            className={`nav-link ${activeView === 'docs' ? 'active' : ''}`}
            onClick={() => setActiveView('docs')}
          >
            <CodeIcon /> How it Works
          </button>
        </div>

        <div className="nav-actions">
          <button 
            className={`dev-toggle ${isDevMode ? 'active' : ''}`}
            onClick={() => setIsDevMode(!isDevMode)}
            title="Toggle Developer Mode"
          >
            <CodeIcon /> {isDevMode ? "API Mode: ON" : "API Mode"}
          </button>
          <div className="nav-badges desktop-only">
            <span className="badge">CAMARA NaC</span>
          </div>
        </div>
      </nav>

      <main className="main-content">
        {activeView === "verify" ? (
          <>
            {/* Verification Input Panel */}
            <section className="glass-panel">
              <div className="hero-stack">
                <h1 className="hero-title">Real-Time Number Intelligence</h1>
                <p className="hero-subtitle">Bypass vulnerable OTPs. Authenticate using direct telecom network signals.</p>
              </div>

              <div className="interactive-form">
                <div className="input-wrapper">
                  <div className="input-icon"><PhoneIcon /></div>
                  <input
                    className="premium-input"
                    placeholder="Enter Target MSISDN (e.g. 08011111111)"
                    value={phone}
                    onChange={e => setPhone(e.target.value)}
                    onKeyDown={handleKeyDown}
                    disabled={simState === "loading"}
                  />
                </div>
                <button
                  className="premium-btn"
                  onClick={() => verify(phone)}
                  disabled={simState === "loading" || !phone}
                >
                  <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                    <SearchIcon />
                    {simState === "loading" ? "Analyzing Signals..." : "Run Security Analysis"}
                  </div>
                </button>
              </div>

              {error && <div className="error-msg" style={{ marginTop: '1rem' }}>{error}</div>}

              {simState === "loading" && (
                <div className="terminal-loader">
                  <div className="t-header">
                    <div className="t-dot r"></div>
                    <div className="t-dot y"></div>
                    <div className="t-dot g"></div>
                  </div>
                  {MOCK_LOADING_STEPS.slice(0, loadStepIndex + 1).map((step, idx) => (
                    <div key={idx} className="t-line">
                      [{new Date().toISOString().split('T')[1].slice(0, 8)}]
                      <span className={idx === loadStepIndex ? "active" : ""}> {step}</span>
                    </div>
                  ))}
                </div>
              )}

              <div className="demo-test-cases">
                <div className="demo-title-group">
                  <h2 className="demo-section-title">Scenario Simulation</h2>
                  <p className="demo-section-subtitle">Click a profile to simulate real-world telecom network signals.</p>
                </div>
                <div className="demo-grid">
                  <button className="demo-card-btn" onClick={() => verify("08011111111")}>
                    <div className="d-icon-wrap safe"><ShieldCheck /></div>
                    <div className="d-info">
                      <span className="d-name">Jane Doe</span>
                      <span className="d-status-tag safe">Clean Profile</span>
                      <span className="d-phone">08011111111</span>
                    </div>
                  </button>

                  <button className="demo-card-btn" onClick={() => verify("08033333333")}>
                    <div className="d-icon-wrap warn"><AlertTriangle /></div>
                    <div className="d-info">
                      <span className="d-name">Unknown User</span>
                      <span className="d-status-tag warn">Anomalous Data</span>
                      <span className="d-phone">08033333333</span>
                    </div>
                  </button>

                  <button className="demo-card-btn" onClick={() => verify("08022222222")}>
                    <div className="d-icon-wrap dang"><ShieldX /></div>
                    <div className="d-info">
                      <span className="d-name">Suspected Intruder</span>
                      <span className="d-status-tag dang">SIM Swapped</span>
                      <span className="d-phone">08022222222</span>
                    </div>
                  </button>
                </div>
              </div>
            </section>

            {/* Results Panel */}
            {result && simState === "done" && (() => {
              const cfg = RISK_CONFIG[result.risk_score];
              return (
                <section
                  className="glass-panel results-dashboard"
                  style={{
                    '--state-color': cfg.col,
                    '--state-bg': cfg.bg,
                    '--state-glow': cfg.glow,
                    '--state-border': cfg.border,
                  } as React.CSSProperties}
                >

                  <div className="score-hero">
                    <div className="score-icon-wrap"><cfg.Icon /></div>
                    <div className="score-info">
                      <div className="sc-title">Network Fraud Risk Score</div>
                      <div className="sc-value">{cfg.label} Score</div>
                    </div>
                  </div>

                  <div className="decision-banner">
                    <cfg.Icon /> Action: <span>{DECISION_OPTS[result.decision]}</span>
                  </div>

                  {result.decision === "STEP_UP" && (
                    <div className="step-up-action">
                      <div className="su-text">
                        <div className="su-title">Requires Step-Up Verification</div>
                        <div className="su-p">Signals indicate anomalous activity (inactive device or unexpected routing). Prompt user for biometric selfie ID check before completing funding.</div>
                      </div>
                      <button className="su-btn" onClick={triggerLiveness}>Liveness Check</button>
                    </div>
                  )}

                  {isDevMode && (
                    <div className="dev-response-panel">
                      <div className="dev-header">
                        <div className="dev-title"><CodeIcon /> Developer Payload (JSON)</div>
                        <button className="copy-btn" onClick={() => {
                          navigator.clipboard.writeText(JSON.stringify(result, null, 2));
                          alert("JSON Copied!");
                        }}>Copy JSON</button>
                      </div>
                      <pre className="code-block">
                        {JSON.stringify(result, null, 2)}
                      </pre>
                    </div>
                  )}

                  <div className="breakdown-grid">

                    <div className="check-card">
                      <div className={`chk-icon ${result.number_verified ? 'pass' : 'fail'}`}>
                        {result.number_verified ? <CheckIcon /> : <XIcon />}
                      </div>
                      <dl className="chk-details">
                        <dt>Number Verification</dt>
                        <dd>{result.number_verified ? "Valid number formatting and operator match." : "Operator mismatch or invalid MSISDN sequence."}</dd>
                      </dl>
                    </div>

                    <div className="check-card">
                      <div className={`chk-icon ${!result.sim_swap_recent ? 'pass' : 'fail'}`}>
                        {!result.sim_swap_recent ? <CheckIcon /> : <XIcon />}
                      </div>
                      <dl className="chk-details">
                        <dt>SIM Swap Defense</dt>
                        <dd>{!result.sim_swap_recent ? "No recent SIM replacement detected (< 48 hrs)." : "CRITICAL: SIM routing changed within last 12 hours!"}</dd>
                      </dl>
                    </div>

                    <div className="check-card">
                      <div className={`chk-icon ${result.device_active ? 'pass' : 'fail'}`}>
                        {result.device_active ? <CheckIcon /> : <AlertTriangle />}
                      </div>
                      <dl className="chk-details">
                        <dt>Device Status</dt>
                        <dd>{result.device_active ? "Device is currently reachable on the carrier network." : "Device is unreachable / powered off. Suspicious."}</dd>
                      </dl>
                    </div>

                    <div className="check-card">
                      <div className={`chk-icon ${result.location_match ? 'pass' : 'fail'}`}>
                        {result.location_match ? <CheckIcon /> : <AlertTriangle />}
                      </div>
                      <dl className="chk-details">
                        <dt>Location Validation</dt>
                        <dd>{result.location_match ? "Network cell tower matches asserted device IP region." : "Cell tower region strongly deviates from IP location."}</dd>
                      </dl>
                    </div>

                  </div>

                  <div className="result-footer">
                    Audited query for MSISDN <strong>{result.phone}</strong> at {new Date(result.timestamp).toLocaleString()}
                  </div>

                </section>
              );
            })()}
          </>
        ) : activeView === "dashboard" ? (
          <section className="dashboard-view animate-fade-in">
            <div className="dashboard-header-stats">
              <div className="stat-card">
                <span className="stat-label">Total Validations (30d)</span>
                <span className="stat-value">{stats?.total_checks.toLocaleString() || '---'}</span>
                <span className="stat-trend positive">↑ 12% vs last month</span>
              </div>
              <div className="stat-card">
                <span className="stat-label">Fraud Prevention Rate</span>
                <span className="stat-value">{stats?.prevention_rate || '---'}</span>
                <span className="stat-hint">Calculated on high-risk blocks</span>
              </div>
              <div className="stat-card">
                <span className="stat-label">Stolen SIMs Blocked</span>
                <span className="stat-value">{stats?.blocked_swaps || '---'}</span>
                <span className="stat-hint">Active SIM swap prevention</span>
              </div>
            </div>

            <div className="dashboard-grid">
              <div className="glass-panel chart-panel">
                <h3 className="panel-title">Verification Volume (Weekly)</h3>
                <div className="simple-bar-chart">
                  {stats?.weekly_trend.map((val: number, i: number) => (
                    <div key={i} className="bar-wrapper" style={{ '--height': `${(val / 80) * 100}%` } as any}>
                      <div className="bar"></div>
                      <span className="bar-label">D{i+1}</span>
                    </div>
                  ))}
                </div>
              </div>
              <div className="glass-panel insights-panel">
                <h3 className="panel-title">Risk Distribution</h3>
                <div className="risk-donut">
                  <div className="donut-segment safe" style={{ flex: stats?.risk_distribution.low }}></div>
                  <div className="donut-segment warn" style={{ flex: stats?.risk_distribution.suspicious }}></div>
                  <div className="donut-segment dang" style={{ flex: stats?.risk_distribution.high }}></div>
                </div>
                <div className="donut-legend">
                  <div className="l-item"><span className="dot safe"></span> Safe ({stats?.risk_distribution.low}%)</div>
                  <div className="l-item"><span className="dot warn"></span> Suspicious ({stats?.risk_distribution.suspicious}%)</div>
                  <div className="l-item"><span className="dot dang"></span> High Risk ({stats?.risk_distribution.high}%)</div>
                </div>
              </div>
            </div>
          </section>
        ) : (
          <section className="docs-view animate-fade-in">
            <div className="docs-hero">
              <h1 className="docs-title">Network Identity Framework</h1>
              <p className="docs-subtitle">Understanding the GSMA Open Gateway Security Layer</p>
            </div>

            <div className="docs-grid">
              <div className="glass-panel doc-card">
                <div className="doc-icon"><ShieldCheck /></div>
                <h3 className="doc-h">Number Verification</h3>
                <p className="doc-p">Directly validates that the SIM card in the device matches the phone number asserted by the user. No SMS OTP required.</p>
              </div>

              <div className="glass-panel doc-card">
                <div className="doc-icon"><AlertTriangle /></div>
                <h3 className="doc-h">SIM Swap Detection</h3>
                <p className="doc-p">Queries the Mobile Operator for the last time a SIM card change occurred. Changes within 24-48 hours trigger high-risk alerts.</p>
              </div>

              <div className="glass-panel doc-card">
                <div className="doc-icon"><PhoneIcon /></div>
                <h3 className="doc-h">Device Status</h3>
                <p className="doc-p">Confirms if the device is currently active on the cellular network. Inactive devices can indicate "SIM-out" fraud scenarios.</p>
              </div>

              <div className="glass-panel doc-card">
                <div className="doc-icon"><SearchIcon /></div>
                <h3 className="doc-h">Location Match</h3>
                <p className="doc-p">Compares the GPS/IP location of the user with the actual Cell Tower (MNC/MCC) the SIM is connected to.</p>
              </div>
            </div>

            <div className="glass-panel system-flow">
              <h3 className="flow-title">Security Orchestration Flow</h3>
              <div className="flow-steps">
                <div className="f-step"><span>1</span> User Input</div>
                <div className="f-arrow">→</div>
                <div className="f-step active"><span>2</span> Telco Enabler</div>
                <div className="f-arrow">→</div>
                <div className="f-step"><span>3</span> Risk Scoring</div>
                <div className="f-arrow">→</div>
                <div className="f-step approve"><span>4</span> Trusted Auth</div>
              </div>
            </div>
          </section>
        )}

      </main>

      {/* Liveness Modal Simulation */}
      {showLiveness && (
        <div className="liveness-modal">
          <div className="liveness-content glass-panel">
            <div className="liveness-header">
              <h2 className="l-title">Biometric Liveness Audit</h2>
              <button className="close-btn" onClick={() => setShowLiveness(false)}><XIcon /></button>
            </div>

            <div className="camera-sim">
               <div className="scanner-line"></div>
               <div className="face-outline">
                 {livenessStatus === 'scanning' ? <UserIcon /> : <CheckIcon />}
               </div>
               <div className="camera-overlay">
                 <div className="c-corner tl"></div>
                 <div className="c-corner tr"></div>
                 <div className="c-corner bl"></div>
                 <div className="c-corner br"></div>
               </div>
            </div>

            <div className="liveness-footer">
              <div className="l-status">
                {livenessStatus === 'scanning' ? (
                  <><span className="spinner"></span> Analyzing facial telemetry...</>
                ) : (
                  <><span className="success-text">✓ Identity Verified Successfully</span></>
                )}
              </div>
              {livenessStatus === 'success' && (
                <button className="premium-btn" style={{padding: '0.8rem 2rem'}} onClick={() => setShowLiveness(false)}>Continue Transaction</button>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
